import flatpickr from "flatpickr";
import "flatpickr/dist/flatpickr.min.css";
import iziToast from "izitoast";
import "izitoast/dist/css/iziToast.min.css";

// Знаходимо елементи інтерфейсу
const startBtn = document.querySelector('button[data-start]');
const datetimePicker = document.querySelector('#datetime-picker');

const daysValue = document.querySelector('[data-days]');
const hoursValue = document.querySelector('[data-hours]');
const minutesValue = document.querySelector('[data-minutes]');
const secondsValue = document.querySelector('[data-seconds]');

let userSelectedDate = null;
let timerId = null;

// Початковий стан кнопки
startBtn.disabled = true;

const options = {
  enableTime: true,
  time_24hr: true,
  defaultDate: new Date(),
  minuteIncrement: 1,
  onClose(selectedDates) {
    const chosenDate = selectedDates[0];
    
    // Змінено оператор з < на <=
    if (chosenDate <= new Date()) {
      // Тепер теперішній момент і минуле вважаються помилкою
      iziToast.error({
        title: 'Error',
        message: 'Please choose a date in the future',
        position: 'topRight',
      });
      startBtn.disabled = true;
      userSelectedDate = null;
    } else {
      userSelectedDate = chosenDate;
      startBtn.disabled = false;
    }
  },
};

flatpickr(datetimePicker, options);

// Слухач подій для кнопки Start
startBtn.addEventListener('click', () => {
  // Блокуємо кнопку та інпут після запуску
  startBtn.disabled = true;
  datetimePicker.disabled = true;

  // Запуск інтервалу
  timerId = setInterval(() => {
    const currentTime = new Date();
    const deltaTime = userSelectedDate - currentTime;

    // Якщо час вичерпано
    if (deltaTime <= 0) {
      clearInterval(timerId);
      updateTimerInterface({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      
      // Розблоковуємо інпут після завершення таймера
      datetimePicker.disabled = false;
      
      iziToast.success({
        title: 'Finished',
        message: 'Countdown has ended!',
        position: 'topRight',
      });
      return;
    }

    // Розрахунок часу та оновлення інтерфейсу
    const timeComponents = convertMs(deltaTime);
    updateTimerInterface(timeComponents);
  }, 1000);
});

// Функція для форматування (додавання ведучого нуля)
function addLeadingZero(value) {
  return String(value).padStart(2, '0');
}

// Функція оновлення текстового вмісту елементів інтерфейсу
function updateTimerInterface({ days, hours, minutes, seconds }) {
  daysValue.textContent = addLeadingZero(days);
  hoursValue.textContent = addLeadingZero(hours);
  minutesValue.textContent = addLeadingZero(minutes);
  secondsValue.textContent = addLeadingZero(seconds);
}

// Готова функція для підрахунку значень
function convertMs(ms) {
  const second = 1000;
  const minute = second * 60;
  const hour = minute * 60;
  const day = hour * 24;

  const days = Math.floor(ms / day);
  const hours = Math.floor((ms % day) / hour);
  const minutes = Math.floor(((ms % day) % hour) / minute);
  const seconds = Math.floor((((ms % day) % hour) % minute) / second);

  return { days, hours, minutes, seconds };
}